    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Beach Vacation Ready - 2w 4x/wk',
    'life_events',
    4,
    60,
    ARRAY['Maximize calorie burn', 'Preserve lean muscle']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Beach Vacation Ready'
ON CONFLICT DO NOTHING;

